import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import response from './response.json';

interface Arrival {
  route: string;
  destination: string;
  arrivalTime: string;
  realTimeDelay: string;
}

interface TransitData {
  station: string;
  nextArrivals: Arrival[];
}

export default function Widget() {
  const transitData = response.data as TransitData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#37474F' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" sx={{ color: '#FFC107', mb: 1 }}>
              {transitData.station}
            </Typography>
            <Typography variant="body2" color="text.secondary" sx={{ color: '#FFFFFF' }}>
              Next Arrivals
            </Typography>
          </Box>

          <Stack spacing={1.5}>
            {transitData.nextArrivals.map((arrival, index) => (
              <Box key={index} sx={{ p: 1, borderRadius: 1, bgcolor: '#455A64' }}>
                <Stack direction="row" justifyContent="space-between" alignItems="center">
                  <Box>
                    <Typography variant="body2" sx={{ color: '#FFC107', fontWeight: 600 }}>
                      {arrival.route}
                    </Typography>
                    <Typography variant="caption" sx={{ color: '#CFD8DC' }}>
                      To {arrival.destination}
                    </Typography>
                  </Box>
                  <Box textAlign="right">
                    <Typography variant="body2" sx={{ color: '#FFFFFF', fontWeight: 500 }}>
                      {arrival.arrivalTime}
                    </Typography>
                    <Typography variant="caption" sx={{ color: arrival.realTimeDelay.includes('+') ? '#FF7043' : '#66BB6A' }}>
                      {arrival.realTimeDelay}
                    </Typography>
                  </Box>
                </Stack>
              </Box>
            ))}
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
